function stripBrand(text: string): string {
  return text
    .replace(/\bpolar\s+camel\b/gi, " ")
    .replace(/\s+([.,])/g, "$1")
    .replace(/\s{2,}/g, " ")
    .trim();
}

function stripBrandSlug(slug: string): string {
  const cleaned = slug
    .replace(/polar-camel-?/g, "")
    .replace(/(^-+)|(-+$)/g, "")
    .replace(/-{2,}/g, "-");
  return cleaned || slug;
}

