/* ------------------------------------------------------------------ */
/* Deterministic derivation helpers                                    */
/* ------------------------------------------------------------------ */

function xmur3(str: string): () => number {
  let h = 1779033703 ^ str.length;
  for (let i = 0; i < str.length; i++) {
    h = Math.imul(h ^ str.charCodeAt(i), 3432918353);
    h = (h << 13) | (h >>> 19);
  }
  return () => {
    h = Math.imul(h ^ (h >>> 16), 2246822507);
    h = Math.imul(h ^ (h >>> 13), 3266489909);
    return (h ^= h >>> 16) >>> 0;
  };
}

function mulberry32(a: number): () => number {
  return () => {
    a |= 0;
    a = (a + 0x6d2b79f5) | 0;
    let t = Math.imul(a ^ (a >>> 15), 1 | a);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

function rngFor(seed: string): () => number {
  return mulberry32(xmur3(seed)());
}

function intBetween(rng: () => number, min: number, max: number): number {
  return Math.floor(rng() * (max - min + 1)) + min;
}

const FONT_OPTIONS = [
  "Classic Serif",
  "Modern Sans",
  "Elegant Script",
  "Block Capitals",
];

function buildPersonalization(): PersonalizationOption[] {
  return [
    {
      id: "font",
      label: "Font style",
      type: "select",
      required: false,
      options: FONT_OPTIONS,
    },
  ];
}

function buildDescriptions(p: RawProduct): {
  description: string;
  longDescription: string;
} {
  const sizePart = p.size ? ` (${p.size})` : "";
  const description = `${p.name}${sizePart}, ready to personalize with laser engraving — add a name, date, monogram or logo for a crisp, permanent finish.`;
  const longDescription = `The ${p.name} is part of our ${p.subName} collection and is precision laser-engraved to order in the USA. Customize it with a name, date, monogram, or your company logo for a sharp, permanent mark that won't fade or peel — ideal for gifts, weddings, corporate orders and milestone awards. ${
    p.size ? `Size: ${p.size}. ` : ""
  }Personalization is included; volume and corporate pricing available on request.`;
  return { description, longDescription };
}

/* ------------------------------------------------------------------ */
/* Build the catalog once at module load                               */
/* ------------------------------------------------------------------ */

const jdsProducts: Product[] = normProducts.map((p) => {
  const rng = rngFor(p.sku);
  const leadTimeDays = intBetween(rng, 5, 14);
  const badges: string[] = [];
  const roll = rng();
  if (roll < 0.14) badges.push("Bestseller");
  else if (roll < 0.26) badges.push("New");
  const { description, longDescription } = buildDescriptions(p);
  const image = p.image ?? p.imageFull ?? "";
  return {
    id: p.id,
    name: p.name,
    sku: p.sku,
    size: p.size,
    basePrice: p.price ?? 0,
    image,
    imageFull: p.imageFull ?? image,
    categoryId: p.categoryId,
    categorySlug: p.categorySlug,
    categoryName: p.categoryName,
    subcategorySlug: p.subSlug,
    subcategoryName: p.subName,
    description,
    longDescription,
    badges,
    leadTimeDays,
    personalization: buildPersonalization(),
  };
});

// Curated multi-view image galleries, keyed by SKU (case-insensitive).
// Source: .scrape/incoming/Product_images bound to catalog SKUs by
// .scrape/overnight/build_image_report.py — the binaries themselves are
// served from /public/products/{SKU}/ but are NOT committed (volume >> 500MB);
// only the URL bindings live in src/data/product-images.json.
const productImagesByUpper = new Map<string, string[]>(
  Object.entries(productImagesRaw as Record<string, string[]>).map(
    ([k, v]) => [k.toUpperCase(), v],
  ),
);

// Per-SKU shipping weight (pounds). Source: FOMA's master spreadsheet,
// stored in src/data/product-weights.json. Surfaced as `Product.weightLb`,
// rendered on the detail page's spec list, AND appended as a sentence to
// the product's longDescription so the lb figure shows up in body copy
// + SEO metadata.
const productWeightsByUpper = new Map<string, number>(
  Object.entries(productWeightsRaw as Record<string, number>).map(
    ([k, v]) => [k.toUpperCase(), v],
  ),
);

// Per-product-type shipping info (dimensions in inches, engraving area
// in mm, and a fallback weight in pounds). Generated by
// .scrape/build_product_shipping.py from the supplier's "Ürün Kargo
// bilgileri.xlsx" master after the catalog was reviewed and the
// type-bucket map was operator-approved. Only the dimensions and the
// engraving-area copy are added to the description here; per-SKU exact
// weights from product-weights.json remain canonical and override the
// fallback.
interface ShippingInfo {
  type: string;
  dim_in: string | null;
  engrave_mm: string | null;
  fallback_weight_lb: number | null;
}
const productShippingByUpper = new Map<string, ShippingInfo>(
  Object.entries(productShippingRaw as Record<string, ShippingInfo>).map(
    ([k, v]) => [k.toUpperCase(), v],
  ),
);

function enrich(p: Product): Product {
  const upper = p.sku.toUpperCase();
  const images = productImagesByUpper.get(upper);
  const exactWeightLb = productWeightsByUpper.get(upper);
  const ship = productShippingByUpper.get(upper);

  let next = p;
  if (images && images.length > 0) next = { ...next, images };

  // `weightLb` is the item weight from the per-SKU master list. It is the
  // value that flows into the existing "Weight" spec chip.
  if (exactWeightLb !== undefined && exactWeightLb > 0) {
    next = { ...next, weightLb: exactWeightLb };
  }

  // The supplier shipping xlsx is keyed per product type — every Wine Tumbler
  // ships the same carton dimensions and the same approximate shipping
  // weight regardless of color. We expose all three fields so the detail
  // page can render them as structured spec chips rather than burying them
  // in description prose.
  if (ship) {
    if (ship.fallback_weight_lb !== null && ship.fallback_weight_lb > 0) {
      next = { ...next, shippingWeightLb: ship.fallback_weight_lb };
    }
    if (ship.dim_in) {
      next = { ...next, dimensions: ship.dim_in };
    }
    if (ship.engrave_mm) {
      next = { ...next, engravingArea: ship.engrave_mm };
    }
    if (ship.type) {
      next = { ...next, shippingType: ship.type };
    }
  }
  return next;
}

// FOMA's own inventory (foma-products.ts) is merged in alongside the reseller
// catalog without altering it. The curated gallery + weight enrichments are
// applied uniformly so any future FOMA SKU can pick up its bindings the same way.
const allProducts: Product[] = [...jdsProducts, ...fomaProducts]
  .map(enrich)
  .map((p) => {
    if (p.categorySlug !== GIFTS_SOURCE_SLUG) return p;
    const t = giftsCategoryFor(p.subcategorySlug);
    return { ...p, categoryId: t.id, categorySlug: t.slug, categoryName: t.name };
  });

const productById = new Map(allProducts.map((p) => [p.id, p]));

const productsByCategory = new Map<string, Product[]>();
const productsBySub = new Map<string, Product[]>();
for (const p of allProducts) {
  const cKey = p.categorySlug;
  const sKey = `${p.categorySlug}/${p.subcategorySlug}`;
  (productsByCategory.get(cKey) ?? productsByCategory.set(cKey, []).get(cKey)!).push(p);
  (productsBySub.get(sKey) ?? productsBySub.set(sKey, []).get(sKey)!).push(p);
}

const categories: Category[] = [...normCategories, FOMA_CATEGORY].map((c) => {
  const subcategories: Subcategory[] = c.subcategories
    .map((sc) => {
      const items = productsBySub.get(`${c.slug}/${sc.slug}`) ?? [];
      return {
        slug: sc.slug,
        name: sc.name,
        blurb: `Personalized ${sc.name.toLowerCase()}, laser-engraved to order.`,
        productCount: items.length,
      };
    })
    // Drop tiles a curation left empty so the grid never shows "0 products".
    .filter((sc) => sc.productCount > 0);
  return {
    slug: c.slug,
    name: c.name,
    blurb: CATEGORY_BLURBS[c.slug] ?? `Personalized ${c.name.toLowerCase()}.`,
    icon: CATEGORY_ICONS[c.slug] ?? DEFAULT_ICON,
    subcategories,
    productCount: productsByCategory.get(c.slug)?.length ?? 0,
  };
});

const categoryBySlug = new Map(categories.map((c) => [c.slug, c]));

/* ------------------------------------------------------------------ */
/* Public API                                                          */
/* ------------------------------------------------------------------ */

export function getCategories(): Category[] {
  return categories;
}

export function getCategory(slug: string): Category | undefined {
  return categoryBySlug.get(slug);
}

export function getSubcategory(
  categorySlug: string,
  subSlug: string,
): { category: Category; subcategory: Subcategory } | undefined {
  const category = categoryBySlug.get(categorySlug);
  const subcategory = category?.subcategories.find((sc) => sc.slug === subSlug);
  if (!category || !subcategory) return undefined;
  return { category, subcategory };
}

export function getProductsByCategory(categorySlug: string): Product[] {
  return productsByCategory.get(categorySlug) ?? [];
}

export function getProductsBySubcategory(
  categorySlug: string,
  subSlug: string,
): Product[] {
  return productsBySub.get(`${categorySlug}/${subSlug}`) ?? [];
}

export function getProduct(id: string): Product | undefined {
  return productById.get(id);
}

export function getAllProducts(): Product[] {
  return allProducts;
}

export function getProductCount(): number {
  return allProducts.length;
}

export function getFeaturedProducts(limit = 8): Product[] {
  const bestsellers = allProducts.filter((p) => p.badges.includes("Bestseller"));
  const pool = bestsellers.length >= limit ? bestsellers : allProducts;
  // Spread across categories for visual variety, then sort by rating.
  const byCat = new Map<string, Product[]>();
  for (const p of pool) {
    (byCat.get(p.categorySlug) ?? byCat.set(p.categorySlug, []).get(p.categorySlug)!).push(p);
  }
  // Deterministic per-SKU order so the featured rail is stable across renders
  // and varied across categories (round-robin below) without relying on ratings.
  const rank = (sku: string) => xmur3(sku)();
  for (const list of byCat.values()) list.sort((a, b) => rank(a.sku) - rank(b.sku));
  const out: Product[] = [];
  let added = true;
  while (out.length < limit && added) {
    added = false;
    for (const list of byCat.values()) {
      const next = list.shift();
      if (next) {
        out.push(next);
        added = true;
        if (out.length >= limit) break;
      }
    }
  }
  return out;
}

export function getRelatedProducts(product: Product, limit = 4): Product[] {
  const sameSub = getProductsBySubcategory(
    product.categorySlug,
    product.subcategorySlug,
  ).filter((p) => p.id !== product.id);
  const sameCat = getProductsByCategory(product.categorySlug).filter(
    (p) =>
      p.id !== product.id && p.subcategorySlug !== product.subcategorySlug,
  );
  return [...sameSub, ...sameCat].slice(0, limit);
}

export function searchProducts(query: string, limit = 48): Product[] {
  const q = query.trim().toLowerCase();
  if (!q) return [];
  const terms = q.split(/\s+/);
  return allProducts
    .filter((p) => {
      const haystack =
        `${p.name} ${p.sku} ${p.categoryName} ${p.subcategoryName}`.toLowerCase();
      return terms.every((t) => haystack.includes(t));
    })
    .slice(0, limit);
}

/** Slim index for client-side live search suggestions. */
export function getSearchIndex(): SearchResult[] {
  return allProducts.map((p) => ({
    id: p.id,
    name: p.name,
    categoryName: p.categoryName,
    subcategoryName: p.subcategoryName,
    categorySlug: p.categorySlug,
    subcategorySlug: p.subcategorySlug,
    basePrice: p.basePrice,
    image: p.image,
  }));
}

